class Program
{
    static void Main()
    {
        var ages = new Dictionary<string, int>();
        ages["Alice"] = 30;
        ages["Bob"] = 25;
        ages.Add("Charlie", 35);

        Console.WriteLine(ages["Alice"]);          // 30
        Console.WriteLine(ages.ContainsKey("Bob")); // True
        Console.WriteLine(ages.Count);              // 3

        ages["Alice"] = 31;  // update
        Console.WriteLine(ages["Alice"]);           // 31
    }
}

