class Program
{
    static void Main()
    {
        var scores = new Dictionary<string, int>
        {
            ["Alice"] = 95,
            ["Bob"] = 87
        };

        if (scores.TryGetValue("Alice", out int aliceScore))
            Console.WriteLine($"Alice: {aliceScore}");  // Alice: 95

        if (scores.TryGetValue("Charlie", out int charlieScore))
            Console.WriteLine($"Charlie: {charlieScore}");
        else
            Console.WriteLine("Charlie not found");  // Charlie not found
    }
}

