class Program
{
    static void Main()
    {
        string s = "abracadabra";
        var freq = new Dictionary<char, int>();
        foreach (char c in s)
            freq[c] = freq.GetValueOrDefault(c) + 1;

        foreach (var (ch, count) in freq)
            Console.WriteLine($"{ch}: {count}");
        // a: 5, b: 2, r: 2, c: 1, d: 1
    }
}

